use heck::ToLowerCamelCase;
use specta::TypeCollection;
use specta::datatype::{DataType, Field, Function, FunctionReturnType, Reference, Struct};
use specta_typescript::{self as ts, Exporter, FrameworkExporter, define};
use specta_typescript::{Error, Layout};
use std::borrow::Cow;
use std::collections::BTreeMap;
use std::path::Path;

const FRAMEWORK_HEADER: &str =
    "// This file has been generated by TauRPC. Do not edit this file manually.";

static PACKAGE_JSON: &str = r#"
{
    "name": ".taurpc",
    "types": "index.ts"
}
"#;

static BOILERPLATE_TS_IMPORT: &str = r#"
import { createTauRPCProxy as createProxy, type InferCommandOutput } from 'taurpc'
"#;

static BOILERPLATE_TS_EXPORT: &str = r#"
export const createTauRPCProxy = () => createProxy<Router>(ARGS_MAP)
export type { InferCommandOutput }
"#;

/// Export the generated TS types with the code necessary for generating the client proxy.
///
/// By default, if the `export_to` attribute was not specified on the procedures macro, there will
/// be nothing exported. Otherwise the code will just be export to the .ts file specified by the user.
pub(super) fn export_types(
    export_path: Option<&'static str>,
    args_map: BTreeMap<String, String>,
    ts: ts::Typescript,
    functions: BTreeMap<String, Vec<Function>>,
    types: TypeCollection,
) -> Result<(), Error> {
    let exporter = Exporter::from(ts);

    let export_path = export_path
        .map(|p| p.into())
        .unwrap_or(default_export_path(&exporter.layout));

    exporter
        .framework_prelude(FRAMEWORK_HEADER)
        .framework_runtime(move |mut exporter| {
            let mut out = String::new();

            out.push_str(&exporter.render_types()?);
            out.push_str(BOILERPLATE_TS_IMPORT);

            out.push_str(r#"const ARGS_MAP = "#);
            out.push_str(
                &serde_json::to_string_pretty(&args_map)
                    .map_err(|err| Error::framework("error stringify argument map", err))?,
            );
            out.push_str(";\n\n");

            out.push_str(
                &generate_functions_router(&functions, &exporter)
                    .map_err(|err| Error::framework("failed to generate router type", err))?,
            );
            out.push_str(BOILERPLATE_TS_EXPORT);

            Ok(out.into())
        })
        .export_to(&*export_path, &types)?;

    if export_path.ends_with("node_modules\\.taurpc\\index.ts") {
        let package_json_path = Path::new(&*export_path)
            .parent()
            .ok_or(Error::framework("", "Failed to create 'package.json' path"))?
            .join("package.json");

        std::fs::write(package_json_path, PACKAGE_JSON)
            .map_err(|err| Error::framework("Failed to create 'package.json' file", err))?
    }

    Ok(())
}

fn generate_functions_router(
    functions: &BTreeMap<String, Vec<Function>>,
    exporter: &FrameworkExporter,
) -> std::result::Result<String, Error> {
    let mut router = Struct::named();

    for (path, path_functions) in functions {
        let mut function_names_and_funcs: Vec<_> =
            path_functions.iter().map(|f| (f.name(), f)).collect();
        function_names_and_funcs.sort_by(|a, b| a.0.cmp(b.0));

        let mut path_router = Struct::named();
        for (_, function) in function_names_and_funcs {
            let (name, field) = generate_function_field(function, exporter)?;
            path_router = path_router.field(name, field);
        }

        router = router.field(path.clone(), Field::new(path_router.build()));
    }

    let router_type = exporter.inline(&router.build())?;
    Ok(format!("export type Router = {router_type};\n"))
}

fn generate_function_field(
    function: &Function,
    exporter: &FrameworkExporter,
) -> std::result::Result<(String, Field), Error> {
    let args = function
        .args()
        .iter()
        .map(|(name, typ)| {
            render_reference_dt(typ, exporter)
                .map(|ty| format!("{}: {ty}", name.to_lower_camel_case()))
        })
        .collect::<std::result::Result<Vec<_>, _>>()?
        .join(", ");

    let return_ty = match function.result() {
        Some(FunctionReturnType::Value(t)) => render_reference_dt(t, exporter)?,
        Some(FunctionReturnType::Result(t, _e)) => render_reference_dt(t, exporter)?,
        None => "void".to_string(),
    };

    let name = function.name().split_once("_taurpc_fn__").unwrap().1;
    Ok((
        name.to_string(),
        Field::new(define(format!("({args}) => Promise<{return_ty}>")).into()),
    ))
}

// Render a `DataType` as a reference (or fallback to inline).
// Also handles Tauri channel references.
fn render_reference_dt(dt: &DataType, exporter: &FrameworkExporter) -> Result<String, Error> {
    if let DataType::Reference(Reference::Named(r)) = dt
        && let Some(ndt) = r.get(exporter.types)
        && ndt.name() == "TAURI_CHANNEL"
        && ndt.module_path().starts_with("tauri::")
    {
        let generic = if let Some((_, dt)) = r.generics().first() {
            match &dt {
                DataType::Reference(r) => exporter.reference(r)?,
                dt => exporter.inline(dt)?,
            }
            .into()
        } else {
            Cow::Borrowed("never")
        };
        Ok(format!("(response: {generic}) => void"))
    } else {
        match &dt {
            DataType::Reference(r) => exporter.reference(r),
            dt => exporter.inline(dt),
        }
    }
}

fn default_export_path(layout: &Layout) -> Cow<'static, str> {
    let default = Cow::Borrowed(if *layout == Layout::Files {
        "bindings"
    } else {
        "bindings.ts"
    });

    let current_dir = match std::env::current_dir() {
        Ok(dir) => dir,
        Err(e) => {
            eprintln!("Error getting current directory: {:?}", e);
            return default;
        }
    };

    match current_dir
        .join("../bindings.ts")
        .into_os_string()
        .into_string()
    {
        Ok(path) => path.into(),
        Err(e) => {
            eprintln!("Error getting default export path: {:?}", e);
            default
        }
    }
}
